/*
* @info Vector Register File
*
* @author VLSI Lab, EE dept., Democritus University of Thrace
*
*/
module vrf #(
    parameter int VREGS      = 32,
    parameter int ELEMENTS   = 4 ,
    parameter int DATA_WIDTH = 32
) (
    input  logic                                           clk         ,
    input  logic                                           reset       ,
    //Element Read Ports
    input  logic [      $clog2(VREGS)-1:0]                 rd_addr_1   ,
    output logic [           ELEMENTS-1:0][DATA_WIDTH-1:0] data_out_1  ,
    input  logic [      $clog2(VREGS)-1:0]                 rd_addr_2   ,
    output logic [           ELEMENTS-1:0][DATA_WIDTH-1:0] data_out_2  ,
    input  logic [      $clog2(VREGS)-1:0]                 mask_src    ,
    output logic [           ELEMENTS-1:0]                 mask        ,
    //Element Write Ports
    input  logic [           ELEMENTS-1:0]                 el_wr_en    ,
    input  logic [      $clog2(VREGS)-1:0]                 el_wr_addr  ,
    input  logic [           ELEMENTS-1:0][DATA_WIDTH-1:0] el_wr_data  ,
    //Register Read Port
    input  logic [      $clog2(VREGS)-1:0]                 v_rd_addr_0 ,
    output logic [ELEMENTS*DATA_WIDTH-1:0]                 v_data_out_0,
    input  logic [      $clog2(VREGS)-1:0]                 v_rd_addr_1 ,
    output logic [ELEMENTS*DATA_WIDTH-1:0]                 v_data_out_1,
    input  logic [      $clog2(VREGS)-1:0]                 v_rd_addr_2 ,
    output logic [ELEMENTS*DATA_WIDTH-1:0]                 v_data_out_2,
    //Register Write Port
    input  logic [           ELEMENTS-1:0]                 v_wr_en     ,
    input  logic [      $clog2(VREGS)-1:0]                 v_wr_addr   ,
    input  logic [ELEMENTS*DATA_WIDTH-1:0]                 v_wr_data
);

    //Internal Signals
    logic [VREGS-1:0][ELEMENTS-1:0][DATA_WIDTH-1:0] memory      ;
    logic [VREGS-1:0]                               wr_addr_oh  ;
    logic [VREGS-1:0]                               v_wr_addr_oh;
    // Convert to one-hot
    assign v_wr_addr_oh = (1 << v_wr_addr);
    assign wr_addr_oh   = (1 << el_wr_addr);
    //Store new Data
    always_ff @(posedge clk) begin : memManage
        if(reset) begin
            for (int k = 0; k < ELEMENTS; k++) begin
                for (int i = 0; i < VREGS; i++) begin
                    memory[i][k] <= 'h0;
                end
            end
        end else begin
            for (int k = 0; k < ELEMENTS; k++) begin
                for (int i = 0; i < VREGS; i++) begin
                    if(v_wr_addr_oh[i] && v_wr_en[k]) begin
                        memory[i][k] <= v_wr_data[k*DATA_WIDTH +: DATA_WIDTH];
                    end else if(wr_addr_oh[i] && el_wr_en[k]) begin
                        memory[i][k] <= el_wr_data[k];
                    end
                end
            end
        end
    end
    // Pick the Data and push them to the Output
    assign v_data_out_0 = memory[v_rd_addr_0];
    assign v_data_out_1 = memory[v_rd_addr_1];
    assign v_data_out_2 = memory[v_rd_addr_2];
    always_comb begin : DataOut
        for (int i = 0; i < ELEMENTS; i++) begin
            data_out_1[i] = memory[rd_addr_1][i];
            data_out_2[i] = memory[rd_addr_2][i];
            mask[i]       = memory[mask_src][i][0];
        end
    end

endmodule

/*
* @info Vector Register Aliasing Table
*
* @author VLSI Lab, EE dept., Democritus University of Thrace
*
*/
module vrat #(
    parameter int TOTAL_ENTRIES = 32,
    parameter int DATA_WIDTH    = 4
) (
    input  logic                             clk        ,
    input  logic                             rst_n      ,
    input  logic                             reconfigure,
    //Write Port
    input  logic [$clog2(TOTAL_ENTRIES)-1:0] write_addr ,
    input  logic [           DATA_WIDTH-1:0] write_data ,
    input  logic                             write_en   ,
    //Read Port #1
    input  logic [$clog2(TOTAL_ENTRIES)-1:0] read_addr_1,
    output logic [           DATA_WIDTH-1:0] read_data_1,
    output logic                             remapped_1 ,
    //Read Port #2
    input  logic [$clog2(TOTAL_ENTRIES)-1:0] read_addr_2,
    output logic [           DATA_WIDTH-1:0] read_data_2,
    output logic                             remapped_2 ,
    //Read Port #3
    input  logic [$clog2(TOTAL_ENTRIES)-1:0] read_addr_3,
    output logic [           DATA_WIDTH-1:0] read_data_3,
    output logic                             remapped_3 ,
    //Mask Port
    output logic [           DATA_WIDTH-1:0] mask_src
);
    localparam ADDR_WIDTH = $clog2(TOTAL_ENTRIES);

    logic [TOTAL_ENTRIES-1:0][DATA_WIDTH-1 : 0] ratMem;
    logic [TOTAL_ENTRIES-1:0] remapped;

    //RAT memory storage
    always_ff @(posedge clk or negedge rst_n) begin : mem
        if(~rst_n) begin
            for (int i = 0; i < TOTAL_ENTRIES; i++) begin
                ratMem[i] <= i;
            end
        end else begin
            if (reconfigure) begin
                ratMem <= 'b0;
            end else if(write_en) begin
                ratMem[write_addr] <= write_data;
            end
        end
    end
    //Register Status Storage (remapped y/n)
    always_ff @(posedge clk or negedge rst_n) begin : remap
        if(~rst_n) begin
            remapped <= 'b1;
        end else begin
            if (reconfigure) begin
                remapped <= 'b0;
            end else if(write_en) begin
                remapped[write_addr] <= 1'b1;
            end
        end
    end
    //Push Data Out
    assign read_data_1 = ratMem[read_addr_1];
    assign remapped_1  = remapped[read_addr_1];
    assign read_data_2 = ratMem[read_addr_2];
    assign remapped_2  = remapped[read_addr_2];
    assign read_data_3 = ratMem[read_addr_3];
    assign remapped_3  = remapped[read_addr_3];

    assign mask_src   = ratMem['d1];


endmodule

